import { getContext, setContext } from "svelte";

const PLAN_CONTEXT_KEY = Symbol("plan-context");

export type PlanContextValue = {
	isStreaming: boolean;
};

export function setPlanContext(value: PlanContextValue) {
	setContext(PLAN_CONTEXT_KEY, value);
}

export function getPlanContext(): PlanContextValue {
	const context = getContext<PlanContextValue>(PLAN_CONTEXT_KEY);
	if (!context) {
		throw new Error("Plan components must be used within Plan");
	}
	return context;
}

import type { HTMLAttributes } from "svelte/elements";
import type { Snippet } from "svelte";
import type { Collapsible as CollapsiblePrimitive } from "bits-ui";

export type PlanProps = CollapsiblePrimitive.RootProps & {
	isStreaming?: boolean;
	class?: string;
	children?: Snippet;
};

export type PlanHeaderProps = HTMLAttributes<HTMLDivElement> & {
	children?: Snippet;
};

export type PlanTitleProps = Omit<HTMLAttributes<HTMLHeadingElement>, "children"> & {
	children: Snippet;
};

export type PlanDescriptionProps = Omit<HTMLAttributes<HTMLParagraphElement>, "children"> & {
	children: Snippet;
};

export type PlanActionProps = HTMLAttributes<HTMLDivElement> & {
	children?: Snippet;
};

export type PlanContentProps = HTMLAttributes<HTMLDivElement> & {
	children?: Snippet;
};

export type PlanFooterProps = HTMLAttributes<HTMLDivElement> & {
	children?: Snippet;
};

export type PlanTriggerProps = CollapsiblePrimitive.TriggerProps & {
	class?: string;
	children?: Snippet;
};

import type { HTMLAttributes } from "svelte/elements";
import type { Snippet } from "svelte";

export type ShimmerProps = HTMLAttributes<HTMLElement> & {
	children: Snippet;
	as?: keyof HTMLElementTagNameMap;
	duration?: number;
	spread?: number;
	content_length?: number;
};

import Shimmer from "./shimmer.svelte";
export { Shimmer };
export type { ShimmerProps } from "./types";

import Plan from "./plan.svelte";
import PlanHeader from "./plan-header.svelte";
import PlanTitle from "./plan-title.svelte";
import PlanDescription from "./plan-description.svelte";
import PlanAction from "./plan-action.svelte";
import PlanContent from "./plan-content.svelte";
import PlanFooter from "./plan-footer.svelte";
import PlanTrigger from "./plan-trigger.svelte";

export type {
	PlanProps,
	PlanHeaderProps,
	PlanTitleProps,
	PlanDescriptionProps,
	PlanActionProps,
	PlanContentProps,
	PlanFooterProps,
	PlanTriggerProps,
} from "./types.js";

export {
	Plan,
	PlanHeader,
	PlanTitle,
	PlanDescription,
	PlanAction,
	PlanContent,
	PlanFooter,
	PlanTrigger,
	//
	Plan as Root,
	PlanTrigger as Trigger,
	PlanContent as Content,
	PlanHeader as Header,
	PlanTitle as Title,
	PlanDescription as Description,
	PlanAction as Action,
	PlanFooter as Footer,
};
